export interface QuizQuestion {
  id: string;
  question: string;
  options: string[];
  correctIndex: number;
  explanation: string;
  category: "identificacion" | "propiedades" | "usos" | "formacion";
}

export interface Quiz {
  id: string;
  title: string;
  description: string;
  icon: string;
  questions: QuizQuestion[];
}

export const QUESTIONS_PER_GAME = 10;

/** Shuffle array using Fisher-Yates */
export function shuffleArray<T>(arr: T[]): T[] {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

export function getRandomQuestions(quiz: Quiz, count = QUESTIONS_PER_GAME): QuizQuestion[] {
  return shuffleArray(quiz.questions).slice(0, count);
}

